**代码调用说明文档**
===

调用签到与回归奖励活动状态模块
---

### FeedCardReturnRewardsWTR 类调用示例

1. 检查回归奖励活动是否允许：

```javascript
const FeedCardReturnRewardsWTR = require("FeedCardReturnRewardsWTR");
FeedCardReturnRewardsWTR.getInstance().isReturnRewardsAllowed();
```

### FeedCardSignInWTR 类调用示例

1. 检查指定天数的签到活动是否允许：

```javascript
const FeedCardSignInWTR = require("FeedCardSignInWTR");
FeedCardSignInWTR.getInstance().isSignInDayEnabled(dayIndex);
```
__注意事项__： 如果你想查询签到活动的第一天是否允许，应传入 `dayIndex = 0`；查询第二天，则传入 `dayIndex = 1`，以此类推。

线上参数配置说明
---

```json
{
	"GameCtrlConfig": {
		"FeedCard": {
			"isOpen": true,
			"config": {
				"cardIdRewardMap": {
					"7536": {"use": "ReturnRewards", "name": "回归用户奖励", "ext": {}},
					"7373": {"use": "SignIn", "name": "新手第1天奖励", "ext": {"signIn":{"dayIndex": 0}}},
					"8201": {"use": "SignIn", "name": "新手第2天奖励", "ext": {"signIn":{"dayIndex": 1}}},
					"8202": {"use": "SignIn", "name": "新手第3天奖励", "ext": {"signIn":{"dayIndex": 2}}},
					"8203": {"use": "SignIn", "name": "新手第4天奖励", "ext": {"signIn":{"dayIndex": 3}}},
					"8204": {"use": "SignIn", "name": "新手第5天奖励", "ext": {"signIn":{"dayIndex": 4}}},
					"8205": {"use": "SignIn", "name": "新手第6天奖励", "ext": {"signIn":{"dayIndex": 5}}},
					"8206": {"use": "SignIn", "name": "新手第7天奖励", "ext": {"signIn":{"dayIndex": 6}}}
				},
				"returnRewardsTimeRange": {
					"startDate": "2024-04-05 16:19:19",
                    "endDate": "2024-05-11 16:19:19"
				},
				"signInTimeRange": {
					"startDate": "2024-04-05 19:05:41",
                    "endDate": "2024-05-11 19:05:41"
				}
			}
		}
	},
}
```
* `cardIdRewardMap`: 奖励卡片的配置， `key` 为`卡片 id` ， `value` 为`卡片奖励配置`，其中 `use` 字段表示`使用哪种奖励`， `name` 字段表示`奖励名称`， `ext` 字段`表示奖励的额外信息`，如 `dayIndex` 表示签到天数（第一天使用数字 `0` ，第二天使用数字 `1` ，以此类推）
* `returnRewardsTimeRange`: 回归奖励活动的时间范围，`startDate` 表示开始日期，`endDate` 表示结束日期
* `signInTimeRange`: 签到活动的时间范围，`startDate` 表示开始日期，`endDate` 表示结束日期
